<template>
    <div class="user">
        <div v-if="showSpinner" class="centred">
            <icon name="spinner" spin scale="2"></icon>
        </div>
        <div v-else-if="showError" class="centred">
            <h1>
                {{$route.params.name}} {{$store.state.data.message}}
            </h1>
        </div>
        <div v-else class="user-maincontent">
            <nav class="centred">
                <img :src="$store.state.data.avatar_url" alt="avatar" class="user-maincontent__avatar">
                <h3 class="user-maincontent__login">
                    <a :href="`https://github.com/${$route.params.name}`">{{$route.params.name}}</a>
                </h3>
            </nav>
            <div class="user-maincontent__content">
                <div class="user-maincontent__navigation">
                    <ul>
                        <li v-for="(item, index) in navMenu" :key="item.key" @click="setChecked(index)"
                            v-bind:class="{ 'checked': checked === item.key }">
                            {{item.menuItem}}
                        </li>
                    </ul>
                </div>
                <user-info v-if="checked == 'about'" :user="$store.state.data"/>
                <repo-list v-if="checked == 'repo'" :repoList="{repos: userRepos, name: $route.params.name}"/>
            </div>
        </div>
    </div>
</template>

<script>
  import {mapActions} from 'vuex'
  import Icon from 'vue-awesome/components/Icon'
  import UserInfo from '../components/UserInfo'
  import RepoList from '../components/RepoList'
  import {userUrl} from '../constants'

  export default {
    data() {
      return {
        navMenu: [
          {menuItem: 'About user', key: 'about'},
          {menuItem: `User's repositories`, key: 'repo'}
        ],
        checked: null,
        userRepos: null
      }
    },
    computed: {
      showSpinner() {
        if(this.$store.state.data === null && this.$store.state.error === null) return true;
        return false;
      },
      showError() {
        if(this.$store.state.data && this.$store.state.data.message) return true;
        return false;
      }
    },
    components: {
      Icon,
      UserInfo,
      RepoList
    },
    methods: {
      ...mapActions({
        getUser: 'getUser'
      }),
      setChecked(index) {
        this.checked = this.navMenu[index].key;
      },
      getUserRepo() {
        fetch(`${userUrl}/users/${this.$route.params.name}/repos`)
          .then(res => res.json().then(result => this.userRepos = result))
      }
    },
    created: function () {
      this.checked = this.navMenu[0].key;
      if (this.$route.params.name) {
        this.getUser(this.$route.params.name)
          .then(() => this.getUserRepo())
      }
    },
    updated: function () {
      if (this.$route.params.name && this.$store.state.data && this.$route.params.name.toLocaleLowerCase() !== this.$store.state.data.login.toLocaleLowerCase()) {
        this.getUser(this.$route.params.name)
          .then(() => {
            this.checked = this.navMenu[0].key;
            this.getUserRepo()
          })
      }
    }
  }
</script>

<style scoped lang="less">
    @import "../assets/less/style";

    .fa-icon {
        color: @main-color;
    }

    .user {
        display: flex;
        width: 100%;
        flex-wrap: wrap;
    }

    .user-maincontent {
        display: flex;
        width: 100%;
        padding: 10px;
    }

    nav {
        width: 250px;
        display: flex;
        flex-direction: column;
        flex-wrap: row;
        justify-content: start;
    }

    .user-maincontent__avatar {
        width: 230px;
        height: 230px;
    }

    .user-maincontent__content {
        display: flex;
        flex-wrap: wrap;
        width: 100%;
        margin: 10px;
    }

    .user-maincontent__navigation {
        .user-maincontent__content;
        height: 50px;
        border-bottom: 1px solid @text-color-main;
    }

    .user-maincontent__login {
        .user-maincontent__content;
    }

    ul {
        display: inline-flex;
        padding: 0;
        margin: 0;
    }

    li {
        list-style-type: none;
        padding: 10px;
        margin: 0;
        &:hover {
            border-bottom: 2px solid @text-color-main;
        }
    }

    .checked {
        font-weight: bold;
        border-bottom: 2px solid;
    }
</style>

