<template>
    <div class="repo">
        <div class="repo-breadcrumbs">
            <icon name="book"/>
            <router-link :to="'/' + $route.params.name">{{$route.params.name}}</router-link>
            <span> / </span>
            <router-link :to="'/' + $route.params.name + '/' + $route.params.repo">{{$route.params.repo}}</router-link>
        </div>
        <div class="centred" v-if="spinner">
            <icon name="spinner" spin scale="2"></icon>
        </div>
        <h1 class="centred" v-if="error">
            {{error}}
        </h1>
        <div v-if="!error && data">
            <div class="row" v-for="item in data" :key="item.label" v-if="item.value">
                <div class="col">
                    {{item.label}}
                </div>
                <div class="col" v-if="typeChecker(item.value) === 'link'">
                    <a :href="item.value">{{item.value}}</a>
                </div>
                <div class="col" v-else-if="typeChecker(item.value) === 'date'">
                    {{moment(item.value, "YYYY-MM-DD").fromNow()}}
                </div>
                <div class="col" v-else>
                    {{item.value}}
                </div>
            </div>
        </div>
    </div>
</template>

<script>
  import {userUrl} from '../constants'
  import Icon from 'vue-awesome/components/Icon'
  import moment from 'moment'
  import * as CONSTANTS from '../constants'

  export default {
    data() {
      return {
        moment,
        data: null,
        spinner: true,
        error: null
      }
    },
    methods: {
      typeChecker(value) {
        if (!value) return false;
        let type = false;
        if (CONSTANTS.URL_REGEXP.test(value)) {
          type = 'link';
        } else if (CONSTANTS.DATE_REGEXP.test(value)) {
          type = 'date';
        }
        return type;
      }
    },
    created: function () {
      fetch(`${userUrl}/repos/${this.$route.params.name}/${this.$route.params.repo}`)
        .then(res => res.json()
          .then(result => {
            this.spinner = false
            if (result.message) {
              this.error = result.message;
            } else {
              this.data = [
                {value: result.name, label: 'Name'},
                {value: result.homepage, label: 'Home page'},
                {value: result.description, label: 'Description'},
                {value: result.created_at, label: 'Created at'},
                {value: result.updated_at, label: 'Updated at'},
                {value: result.forks, label: 'Forks'},
                {value: result.language, label: 'Language'},
                {value: result.license ? result.license.spdx_id : null, label: 'License'},
                {value: result.open_issues, label: 'Open ussues'},
                {value: result.size, label: 'Size'},
                {value: result.stargazers_count, label: 'Stars'},
                {value: result.subscribers_count, label: 'Subscribers'},
                {value: result.watchers, label: 'Watchers'}
              ]
            }
          })
        )
        .catch(err => {
          this.spinner = false
          if (err && err.message) {
            this.error = err.message
          }
        })
    },
    components: {
      Icon
    },
  }
</script>

<style scoped lang="less">
    @import "../assets/less/style";

    .repo {
        width: 100%;
        margin: 10px;
    }

    .repo-breadcrumbs {
        display: flex;
        align-items: center;
        width: 100%;
        margin: 10px 0 10px 0;
    }

    .fa-icon {
        color: #aaa;
    }

    .row {
        display: inline-flex;
        width: 100%;
    }

    .col {
        display: flex;
        width: 45%;
    }
</style>
